import React, { useState, useEffect } from "react";
import toast from "react-hot-toast";
import Card from "../components/Card";
import SignalBadge from "../components/SignalBadge";
import { fetchPortfolio, addHolding, removeHolding, fetchSignal } from "../utils/api";

export default function PortfolioPage() {
  const [holdings, setHoldings] = useState([]);
  const [signals, setSignals] = useState({});
  const [loadingSignal, setLoadingSignal] = useState({});
  const [form, setForm] = useState({ ticker: "", name: "", quantity: "", buyPrice: "" });
  const [adding, setAdding] = useState(false);

  const load = async () => {
    try {
      const data = await fetchPortfolio();
      setHoldings(data);
    } catch {}
  };

  useEffect(() => { load(); }, []);

  const add = async () => {
    if (!form.ticker || !form.quantity || !form.buyPrice) {
      toast.error("Ticker, quantity and buy price are required");
      return;
    }
    setAdding(true);
    try {
      await addHolding(form);
      toast.success("Holding added");
      setForm({ ticker: "", name: "", quantity: "", buyPrice: "" });
      load();
    } catch {
      toast.error("Failed to add holding");
    } finally {
      setAdding(false);
    }
  };

  const remove = async (id) => {
    try {
      await removeHolding(id);
      setHoldings((h) => h.filter((x) => x.id !== id));
      toast.success("Holding removed");
    } catch {
      toast.error("Failed to remove");
    }
  };

  const getSignal = async (ticker) => {
    setLoadingSignal((p) => ({ ...p, [ticker]: true }));
    try {
      const data = await fetchSignal(ticker);
      setSignals((p) => ({ ...p, [ticker]: data }));
    } catch {
      toast.error(`Failed to get signal for ${ticker}`);
    } finally {
      setLoadingSignal((p) => ({ ...p, [ticker]: false }));
    }
  };

  const inputStyle = {
    background: "var(--bg-elevated)",
    border: "1px solid var(--border)",
    color: "var(--text-primary)",
    padding: "10px 14px",
    fontFamily: "var(--font-mono)",
    fontSize: "13px",
    borderRadius: "4px",
    outline: "none",
    width: "100%",
  };

  const totalCost = holdings.reduce((s, h) => s + h.quantity * h.buyPrice, 0);

  return (
    <div>
      <div style={{ marginBottom: "28px" }}>
        <h1 style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: "24px", marginBottom: "4px" }}>
          ◻ Portfolio
        </h1>
        <p style={{ color: "var(--text-secondary)", fontSize: "13px" }}>
          Track your holdings · Get ML signals for each position
        </p>
      </div>

      {/* Summary */}
      {holdings.length > 0 && (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "16px", marginBottom: "24px" }}>
          <div style={{ background: "var(--bg-card)", border: "1px solid var(--border)", borderRadius: "6px", padding: "16px" }}>
            <div style={{ fontSize: "11px", color: "var(--text-dim)", marginBottom: "6px" }}>HOLDINGS</div>
            <div style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: "24px" }}>{holdings.length}</div>
          </div>
          <div style={{ background: "var(--bg-card)", border: "1px solid var(--border)", borderRadius: "6px", padding: "16px" }}>
            <div style={{ fontSize: "11px", color: "var(--text-dim)", marginBottom: "6px" }}>TOTAL INVESTED</div>
            <div style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: "24px" }}>
              ₹{totalCost.toLocaleString("en-IN", { maximumFractionDigits: 0 })}
            </div>
          </div>
          <div style={{ background: "var(--bg-card)", border: "1px solid var(--border)", borderRadius: "6px", padding: "16px" }}>
            <div style={{ fontSize: "11px", color: "var(--text-dim)", marginBottom: "6px" }}>SIGNALS FETCHED</div>
            <div style={{ fontFamily: "var(--font-display)", fontWeight: 800, fontSize: "24px" }}>{Object.keys(signals).length}</div>
          </div>
        </div>
      )}

      {/* Add Holding */}
      <Card title="Add Holding" style={{ marginBottom: "24px" }}>
        <div style={{ display: "grid", gridTemplateColumns: "2fr 2fr 1fr 1fr auto", gap: "12px", alignItems: "end" }}>
          <div>
            <label style={{ fontSize: "11px", color: "var(--text-dim)", display: "block", marginBottom: "6px" }}>TICKER</label>
            <input value={form.ticker} onChange={(e) => setForm((f) => ({ ...f, ticker: e.target.value.toUpperCase() }))} placeholder="RELIANCE.NS" style={inputStyle} />
          </div>
          <div>
            <label style={{ fontSize: "11px", color: "var(--text-dim)", display: "block", marginBottom: "6px" }}>NAME (optional)</label>
            <input value={form.name} onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))} placeholder="Reliance Industries" style={inputStyle} />
          </div>
          <div>
            <label style={{ fontSize: "11px", color: "var(--text-dim)", display: "block", marginBottom: "6px" }}>QUANTITY</label>
            <input value={form.quantity} onChange={(e) => setForm((f) => ({ ...f, quantity: e.target.value }))} placeholder="10" type="number" style={inputStyle} />
          </div>
          <div>
            <label style={{ fontSize: "11px", color: "var(--text-dim)", display: "block", marginBottom: "6px" }}>BUY PRICE</label>
            <input value={form.buyPrice} onChange={(e) => setForm((f) => ({ ...f, buyPrice: e.target.value }))} placeholder="2500" type="number" style={inputStyle} />
          </div>
          <button
            onClick={add}
            disabled={adding}
            style={{ background: "var(--accent-green)", color: "#000", border: "none", padding: "10px 20px", fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "13px", borderRadius: "4px", cursor: "pointer", whiteSpace: "nowrap" }}
          >
            + Add
          </button>
        </div>
      </Card>

      {/* Holdings Table */}
      <Card title="Holdings" subtitle="Click 'Signal' to run ML analysis on any position">
        {holdings.length === 0 ? (
          <div style={{ textAlign: "center", padding: "40px", color: "var(--text-dim)", fontSize: "13px" }}>
            No holdings yet. Add your first position above.
          </div>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "13px" }}>
              <thead>
                <tr style={{ borderBottom: "1px solid var(--border)" }}>
                  {["Ticker", "Name", "Qty", "Buy Price", "Invested", "Signal", "Actions"].map((h) => (
                    <th key={h} style={{ padding: "10px 12px", textAlign: "left", fontSize: "11px", color: "var(--text-dim)", fontWeight: 400, letterSpacing: "0.05em" }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {holdings.map((h) => {
                  const sig = signals[h.ticker];
                  const invested = (h.quantity * h.buyPrice).toLocaleString("en-IN", { maximumFractionDigits: 0 });
                  return (
                    <tr key={h.id} style={{ borderBottom: "1px solid var(--border)" }}>
                      <td style={{ padding: "14px 12px", fontFamily: "var(--font-display)", fontWeight: 700 }}>{h.ticker}</td>
                      <td style={{ padding: "14px 12px", color: "var(--text-secondary)" }}>{h.name}</td>
                      <td style={{ padding: "14px 12px" }}>{h.quantity}</td>
                      <td style={{ padding: "14px 12px" }}>₹{h.buyPrice.toLocaleString("en-IN")}</td>
                      <td style={{ padding: "14px 12px" }}>₹{invested}</td>
                      <td style={{ padding: "14px 12px" }}>
                        {sig ? (
                          <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
                            <SignalBadge signal={sig.signal} confidence={sig.confidence} />
                            {sig.pct_change_1d !== undefined && (
                              <span style={{ fontSize: "11px", color: sig.pct_change_1d >= 0 ? "var(--accent-green)" : "var(--accent-red)" }}>
                                {sig.pct_change_1d >= 0 ? "+" : ""}{sig.pct_change_1d.toFixed(2)}%
                              </span>
                            )}
                          </div>
                        ) : (
                          <button
                            onClick={() => getSignal(h.ticker)}
                            disabled={loadingSignal[h.ticker]}
                            style={{ background: "transparent", border: "1px solid var(--accent-blue)", color: "var(--accent-blue)", padding: "5px 12px", fontFamily: "var(--font-mono)", fontSize: "11px", borderRadius: "3px", cursor: "pointer" }}
                          >
                            {loadingSignal[h.ticker] ? "..." : "⚡ Signal"}
                          </button>
                        )}
                      </td>
                      <td style={{ padding: "14px 12px" }}>
                        <button
                          onClick={() => remove(h.id)}
                          style={{ background: "transparent", border: "1px solid var(--accent-red)", color: "var(--accent-red)", padding: "5px 10px", fontFamily: "var(--font-mono)", fontSize: "11px", borderRadius: "3px", cursor: "pointer" }}
                        >
                          ✕
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </Card>
    </div>
  );
}
